@app.route('/api/audio/devices', methods=['GET'])
def get_audio_devices():
    """API: Lista todos os dispositivos de áudio disponíveis"""
    try:
        devices = sd.query_devices()
        input_devices = []

        for i, dev in enumerate(devices):
            if dev['max_input_channels'] > 0:
                device_info = {
                    'id': i,
                    'name': dev['name'],
                    'channels': dev['max_input_channels'],
                    'sample_rate': dev['default_samplerate']
                }

                # Mark if it's the default device
                try:
                    default_device = sd.default.device[0]
                    if i == default_device:
                        device_info['default'] = True
                except (OSError, RuntimeError):
                    pass

                input_devices.append(device_info)

        # Get current configured device
        deepgram_config = load_deepgram_config()
        current_device = deepgram_config.get('audio_settings', {}).get('input_device')

        return jsonify({
            'devices': input_devices,
            'current_device': current_device
        })
    except Exception as e:
        return jsonify({'error': f'Erro ao listar dispositivos: {str(e)}'}), 500

@app.route('/api/audio/device', methods=['POST'])
def set_audio_device():
    """API: Define o dispositivo de áudio a ser usado"""
    try:
        data = request.json
        device_id = data.get('device_id')

        # Validate device_id if provided (can be null for system default)
        if device_id is not None:
            try:
                device_id = int(device_id)
                # Check if device exists and has input channels
                dev = sd.query_devices(device_id)
                if dev['max_input_channels'] <= 0:
                    return jsonify({'error': 'Dispositivo não possui canais de entrada'}), 400
            except (ValueError, Exception):
                return jsonify({'error': 'ID de dispositivo inválido'}), 400

        # Update config
        config = load_deepgram_config()
        if 'audio_settings' not in config:
            config['audio_settings'] = {}

        config['audio_settings']['input_device'] = device_id
        save_deepgram_config(config)

        device_name = 'Padrão do Sistema' if device_id is None else sd.query_devices(device_id)['name']

        return jsonify({
            'success': True,
            'message': f'Dispositivo de áudio definido: {device_name}',
            'device_id': device_id
        })
    except Exception as e:
        return jsonify({'error': f'Erro ao definir dispositivo: {str(e)}'}), 500

