@app.route('/api/tts/speak', methods=['POST'])
def tts_speak():
    """API: Converte texto para fala e reproduz áudio"""
    try:
        from tts_service import TTSService, ensure_audio_directory, generate_audio_filename
        from audio_player import AudioPlayer

        data = request.json
        text = data.get('text', '').strip()
        voice_id = data.get('voice_id')
        language = data.get('language', 'pt')
        play = data.get('play', True)

        if not text:
            return jsonify({'error': 'Texto é obrigatório'}), 400

        api_key = load_cartesia_config()
        if not api_key:
            return jsonify({
                'error': 'Chave API do Cartesia não configurada',
                'message': 'Configure a chave API do Cartesia em /api/cartesia/config'
            }), 400

        logger.info(f"TTS request: text='{text[:50]}...', voice_id={voice_id}, language={language}")

        # Initialize TTS service
        tts_service = TTSService(api_key)

        # Convert text to speech
        audio_bytes, content_type = tts_service.text_to_speech(text, voice_id, language)

        # Generate filename and ensure directory exists
        date_dir = ensure_audio_directory()
        filename = generate_audio_filename(text)
        file_path = date_dir / filename

        # Save audio file
        with open(file_path, 'wb') as f:
            f.write(audio_bytes)

        logger.info(f"Audio saved to: {file_path}")

        # Play audio if requested
        if play:
            player = AudioPlayer()
            if not player.play_audio_bytes(audio_bytes):
                logger.warning("Audio playback failed, but file was saved")

        return jsonify({
            'success': True,
            'file_path': str(file_path),
            'filename': filename,
            'text': text,
            'voice_id': voice_id,
            'language': language
        })

    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        logger.error(f"TTS error: {str(e)}")
        return jsonify({'error': f'Erro ao processar TTS: {str(e)}'}), 500

@app.route('/api/tts/webhook', methods=['POST'])
def tts_webhook():
    """API: Webhook-compatible endpoint para TTS (compatível com n8n)"""
    result = tts_speak()

    # Check if tts_speak returned an error response
    if isinstance(result, tuple) and result[1] >= 400:
        return result

    # Convert to n8n-compatible response format
    response_data = result.get_json()
    response_data['webhook'] = True
    response_data['timestamp'] = json.dumps({'_': 'now'})

    return jsonify(response_data)

@app.route('/api/tts/history', methods=['GET'])
def get_tts_history():
    """API: Lista arquivos de áudio gerados recentemente"""
    try:
        from pathlib import Path

        audio_dir = Path('audios_files')
        if not audio_dir.exists():
            return jsonify({'files': []})

        files = []
        # Walk through all subdirectories
        for wav_file in audio_dir.rglob('*.wav'):
            stat = wav_file.stat()
            files.append({
                'path': str(wav_file),
                'name': wav_file.name,
                'size': stat.st_size,
                'created': stat.st_ctime
            })

        # Sort by creation time (newest first)
        files.sort(key=lambda x: x['created'], reverse=True)

        # Return only last 50 files
        return jsonify({'files': files[:50]})

    except Exception as e:
        return jsonify({'error': f'Erro ao obter histórico: {str(e)}'}), 500

